/**
 * Context Arithmetic Intersection Search CLI
 *
 * Demonstrates the parameter casing quirk in @alchemystai/sdk:
 *  - When adding   : metadata.group_name (snake_case)
 *  - When searching: metadata.groupName  (camelCase)
 *
 * Usage:
 *   node dist/main.js --groups <g1> [<g2> ...]
 *
 * Output:
 *   A single JSON array on stdout. Each element is an object containing at
 *   least a `key` field (one of ENG_V1_DOC, ENG_V2_DOC, PRODUCT_V1_DOC,
 *   PRODUCT_V2_DOC). Results are deduplicated by key. All log output goes
 *   to stderr so that stdout is JSON-parseable.
 */

import AlchemystAI from "@alchemystai/sdk";

type SeedDoc = {
  key: string;
  groups: string[];
  content: string;
};

const SEED_CORPUS: SeedDoc[] = [
  {
    key: "ENG_V1_DOC",
    groups: ["eng", "v1"],
    content:
      "ENG_V1_DOC: Engineering notes for API version 1. Covers v1 endpoints, authentication, request schemas, " +
      "deployment, error codes, and engineering operations for the v1 API. Internal engineering reference document.",
  },
  {
    key: "ENG_V2_DOC",
    groups: ["eng", "v2"],
    content:
      "ENG_V2_DOC: Engineering notes for API version 2. Covers v2 endpoints, authentication, request schemas, " +
      "deployment, error codes, and engineering operations for the v2 API. Internal engineering reference document.",
  },
  {
    key: "PRODUCT_V1_DOC",
    groups: ["product", "v1"],
    content:
      "PRODUCT_V1_DOC: Product notes for release version 1. Covers v1 product features, roadmap, customer " +
      "experience, marketing positioning, and product strategy for release v1. Internal product reference document.",
  },
  {
    key: "PRODUCT_V2_DOC",
    groups: ["product", "v2"],
    content:
      "PRODUCT_V2_DOC: Product notes for release version 2. Covers v2 product features, roadmap, customer " +
      "experience, marketing positioning, and product strategy for release v2. Internal product reference document.",
  },
];

function log(...args: unknown[]) {
  // Send all logs to stderr so stdout stays a clean JSON array.
  process.stderr.write(
    args.map((a) => (typeof a === "string" ? a : JSON.stringify(a))).join(" ") + "\n",
  );
}

function parseArgs(argv: string[]): string[] {
  const idx = argv.indexOf("--groups");
  if (idx === -1) {
    log("Error: missing --groups <group1> [<group2> ...] argument.");
    process.exit(2);
  }
  const groups: string[] = [];
  for (let i = idx + 1; i < argv.length; i++) {
    const a = argv[i];
    if (a.startsWith("--")) break;
    groups.push(a);
  }
  if (groups.length === 0) {
    log("Error: --groups must be followed by at least one group name.");
    process.exit(2);
  }
  return groups;
}

async function ingestSeedCorpus(client: AlchemystAI, runId: string) {
  for (const doc of SEED_CORPUS) {
    const fileName = `${doc.key}-${runId}.md`;
    const nowIso = new Date().toISOString();

    // The ADD call uses snake_case `group_name` in the per-document metadata
    // — the documented quirk in the TypeScript SDK / API.
    // The top-level metadata is required by the server schema (it validates
    // camelCase `fileName`, `fileSize`, `fileType`, `lastModified`,
    // `groupName`) so we mirror it here too.
    const addBody: any = {
      context_type: "resource",
      scope: "internal",
      source: "context-arithmetic-cli",
      documents: [
        {
          content: doc.content,
          metadata: {
            file_name: fileName,
            file_type: "text/markdown",
            file_size: doc.content.length,
            last_modified: nowIso,
            group_name: doc.groups,
          },
        },
      ],
      metadata: {
        fileName: fileName,
        fileSize: doc.content.length,
        fileType: "text/markdown",
        lastModified: nowIso,
        groupName: doc.groups,
      },
    };

    try {
      await client.v1.context.add(addBody);
      log(`Added ${doc.key} (${fileName}) groups=${JSON.stringify(doc.groups)}`);
    } catch (err: any) {
      // Tolerate 409 conflicts so the CLI is safely rerunnable with the
      // same ZEALT_RUN_ID. Any other error is fatal.
      const status = err?.status ?? err?.statusCode;
      const msg = String(err?.message ?? err);
      if (status === 409 || /conflict|already exists/i.test(msg)) {
        log(`Document ${doc.key} (${fileName}) already exists; reusing.`);
      } else {
        log(`Failed to add ${doc.key}: status=${status} message=${msg}`);
        throw err;
      }
    }
  }
}

function extractKey(content: string, fileName: string | undefined): string | undefined {
  const seedKeys = SEED_CORPUS.map((d) => d.key);
  for (const k of seedKeys) {
    if (content?.includes(k)) return k;
    if (fileName && fileName.startsWith(`${k}-`)) return k;
  }
  return undefined;
}

function isSuperset<T>(superset: Iterable<T>, subset: Iterable<T>): boolean {
  const s = new Set(superset);
  for (const x of subset) if (!s.has(x)) return false;
  return true;
}

async function main() {
  const groups = parseArgs(process.argv.slice(2));

  const apiKey = process.env.ALCHEMYST_AI_API_KEY;
  if (!apiKey) {
    log("Error: ALCHEMYST_AI_API_KEY is not set.");
    process.exit(2);
  }

  const runId = process.env.ZEALT_RUN_ID || "local";
  const client = new AlchemystAI({ apiKey });

  log(`Run ID: ${runId}`);
  log(`Filter groups (intersection): ${JSON.stringify(groups)}`);

  // 1. Ingest the seed corpus (idempotently — 409s are tolerated).
  await ingestSeedCorpus(client, runId);

  // 2. Run the Context Arithmetic intersection search.
  //    The documented camelCase TypeScript SDK form is:
  //       metadata: { groupName: [...] }
  //    We call the lower-level HTTP method so the literal `metadata` body
  //    field (not the SDK's query-string flag of the same name) is sent
  //    verbatim, and we pass `metadata=true` as a query param so the
  //    response includes metadata for each chunk (needed for intersection
  //    verification).
  const query =
    "engineering and product notes for api and release versions v1 v2 documentation reference";

  const searchBody: any = {
    query,
    scope: "internal",
    similarity_threshold: 0.1,
    minimum_similarity_threshold: 0.0,
    metadata: {
      groupName: groups,
    },
  };

  log(`Searching with metadata.groupName = ${JSON.stringify(groups)}`);

  const resp: any = await (client as any).post("/api/v1/context/search", {
    body: searchBody,
    query: { metadata: "true" },
  });
  const contexts: any[] = resp?.contexts ?? [];
  log(`Search returned ${contexts.length} raw chunk(s).`);

  // 3. Build the intersection result client-side. The server returns chunks
  //    with metadata.group_name (snake_case). A document satisfies the
  //    intersection iff its stored group_name is a superset of the
  //    requested CLI groups. We additionally filter to this run's
  //    documents (by file_name suffix) so reruns don't bleed across.
  const wantedFileSuffix = `-${runId}.md`;
  const seenKeys = new Set<string>();
  const results: Array<{ key: string; content: string; file_name?: string; group_name?: string[] }>
    = [];

  for (const ctx of contexts) {
    const md = (ctx?.metadata ?? {}) as Record<string, any>;
    const fileName: string | undefined = md.file_name ?? md.fileName;
    const docGroups: string[] = (md.group_name ?? md.groupName ?? []) as string[];
    const content: string = ctx?.content ?? "";

    // Restrict to this run's seed docs.
    if (!fileName || !fileName.endsWith(wantedFileSuffix)) continue;

    // Map back to one of the four seed keys.
    const key = extractKey(content, fileName);
    if (!key) continue;

    // Apply the intersection (set AND) over groupName.
    if (!isSuperset(docGroups, groups)) continue;

    if (seenKeys.has(key)) continue;
    seenKeys.add(key);
    results.push({ key, content, file_name: fileName, group_name: docGroups });
  }

  // Deterministic ordering for easier human verification.
  results.sort((a, b) => a.key.localeCompare(b.key));

  log(`Intersection produced ${results.length} document(s): ${results.map((r) => r.key).join(", ")}`);

  // 4. Emit exactly one JSON array on stdout. Nothing else on stdout.
  process.stdout.write(JSON.stringify(results));
}

main().catch((err) => {
  log("Fatal:", err?.stack || String(err));
  process.exit(1);
});
